mapper.select:
SELECT q.* FROM question q
INNER JOIN exam_question eq ON q.id = eq.question_id
WHERE eq.exam_id = #{examId}

mapper.update:
UPDATE question SET subject_id=#{subjectId}, type=#{type}, content=#{content},
option_a=#{optionA}, option_b=#{optionB}, option_c=#{optionC}, option_d=#{optionD},
answer=#{answer}, score=#{score}
WHERE id=#{id}
